"    if (type === 'register') {
      let attemptEmail = baseEmail;
      let response: any = null;
      let isSuccess = false;
      const parts = baseEmail.split('@');
      const prefix = parts[0];
      const domain = parts[1];

      for (let i = 0; i <= 20; i++) {
        attemptEmail = i === 0 ? baseEmail : `${prefix}+${i}@${domain}`;

        // Check if this attemptEmail already exists by doing a dummy auth send-code check
        const checkResponse = await postReqWithoutToken('/auth/send-code', {
          email: attemptEmail,
          password: 'DummyPassword123!',
          type: 'auth',
        });

        const checkErrorMsg = (checkResponse?.message || checkResponse?.error?.message || checkResponse?.error || '').toLowerCase();
        const emailExists = !(checkErrorMsg.includes('not exist') || checkErrorMsg.includes('not found') || checkErrorMsg.includes('no user'));

        if (emailExists) {
          // Email is already in use, try the next suffix
          continue;
        }

        // Email is not in use, request registration code
        response = await postReqWithoutToken('/auth/send-code', {
          email: attemptEmail,
          password: password,
          type: type,
        });

        isSuccess = response && 
          response.status !== false && 
          response.status !== 500 && 
          response.status !== 400 && 
          (response.email || response.data || response.status === true || response.status === 200 || response.status === 201);

        if (isSuccess) {
          if (typeof window !== 'undefined') {
            sessionStorage.setItem('temp_register_email', attemptEmail);
          }
          return response.data || response;
        }

        // If it failed because of resend limit or other reasons (not duplicate email), break and report error
        break;
      }

      showErrorMessage(response?.message || response?.error?.message || 'Failed to send verification code');
      return false;"

